#include <iostream>
#include <vector>

using namespace std;

void bubbleSort(vector<int> &numbers)
{
    for (int i = 0; i < numbers.size() - 1; i++)
    {
        for (int j = 0; j < numbers.size() - 1 - i; j++)
        {
            if (numbers[j] > numbers[j + 1])
            {
                swap(numbers[j], numbers[j + 1]); // adjacent swap
            }
        }
    }
}

int main()
{
    vector<int> numbers = {5, 2, 4, 1, 3};

    bubbleSort(numbers);

    for (int n : numbers)
    {
        cout << n << " ";
    }

    return 0;
}

